import React, { useState, useEffect, useRef } from 'react';
import { DiscoveryOptionButton } from './DiscoveryOptionButton.js';
import type { DiscoveryAnswer } from './DiscoveryOptionButton.js';
import { DiscoveryAutocomplete } from './DiscoveryAutocomplete.js';
import type { AnswerChoice } from './DiscoveryAutocomplete.js';

export type AnswerRenderHint = 'choice' | 'autocomplete' | 'searchable_dropdown';

export interface DiscoveryQuestion {
    id: string;
    question: string;
    answers: DiscoveryAnswer[];
    answerRenderHint?: AnswerRenderHint;
    answerChoices?: AnswerChoice[] | null;
    [key: string]: unknown;
}

export interface OtherError {
    message: string;
}

export interface DiscoveryQuestionStepProps {
    question: DiscoveryQuestion;
    selectedAnswer?: { answer_id?: string; answer?: string; [key: string]: unknown } | null;
    onSelectAnswer: (answer: DiscoveryAnswer) => void;
    /**
     * Invoked when the user picks a Critical Filter Question choice
     * (autocomplete / searchable_dropdown render hints). The picked choice's
     * `value` is submitted as `answer_text` with `answer_id: null`.
     */
    onSelectChoice?: (choice: AnswerChoice) => void;
    onOtherSubmit?: (questionId: string, text: string) => void;
    isOtherProcessing?: boolean;
    otherError?: OtherError | null;
    clarificationPrompt?: string | null;
    onClearOtherError?: () => void;
    maxOtherLength?: number;
}

const LoadingSpinner = () => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="omniguide-other-input__spinner">
        <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeDasharray="31.4 31.4" />
    </svg>
);

export function DiscoveryQuestionStep({
    question,
    selectedAnswer,
    onSelectAnswer,
    onSelectChoice,
    onOtherSubmit,
    isOtherProcessing = false,
    otherError = null,
    clarificationPrompt = null,
    onClearOtherError,
    maxOtherLength = 50,
}: DiscoveryQuestionStepProps): JSX.Element {
    const renderHint = question.answerRenderHint ?? 'choice';
    // Fall back to the pill list if the choice renderer can't be used (no
    // handler wired, or no choices shipped).
    const useChoiceRenderer =
        renderHint !== 'choice' &&
        !!onSelectChoice &&
        Array.isArray(question.answerChoices) &&
        question.answerChoices.length > 0;
    const [isOtherMode, setIsOtherMode] = useState(false);
    const [otherText, setOtherText] = useState('');
    const inputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        setIsOtherMode(false);
        setOtherText('');
    }, [question?.id]);

    useEffect(() => {
        if (isOtherMode && inputRef.current) {
            inputRef.current.focus();
        }
    }, [isOtherMode]);

    const handleOtherClick = () => {
        setIsOtherMode(true);
    };

    const handleCancelOther = () => {
        setIsOtherMode(false);
        setOtherText('');
        onClearOtherError?.();
    };

    const handleOtherTextChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value;
        if (value.length <= maxOtherLength) {
            setOtherText(value);
            if (onClearOtherError && otherError) {
                onClearOtherError();
            }
        }
    };

    const handleOtherSubmit = () => {
        if (!otherText.trim() || isOtherProcessing) return;
        onOtherSubmit?.(question.id, otherText.trim());
    };

    const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleOtherSubmit();
        } else if (e.key === 'Escape') {
            handleCancelOther();
        }
    };

    if (useChoiceRenderer && onSelectChoice) {
        return (
            <div className="omniguide-pr-questionnaire__choices">
                <DiscoveryAutocomplete
                    questionId={question.id}
                    choices={question.answerChoices ?? []}
                    onSelectChoice={onSelectChoice}
                    selectedValue={selectedAnswer?.answer ?? null}
                    ariaLabel={question.question}
                    renderHint={renderHint === 'searchable_dropdown' ? 'searchable_dropdown' : 'autocomplete'}
                />
            </div>
        );
    }

    return (
        <div className="omniguide-pr-questionnaire__choices" role="radiogroup" aria-label={question.question}>
            {question.answers.map((answer) => (
                <DiscoveryOptionButton
                    key={answer.id}
                    answer={answer}
                    isSelected={selectedAnswer?.answer_id === answer.id}
                    onSelect={onSelectAnswer}
                />
            ))}

            {onOtherSubmit && !isOtherMode && (
                <button
                    type="button"
                    className="omniguide-pr-option-pill omniguide-pr-option-pill--other"
                    onClick={handleOtherClick}
                    aria-pressed={false}
                >
                    <span className="omniguide-pr-option-pill__text">Other...</span>
                </button>
            )}

            {isOtherMode && (
                <div className="omniguide-other-input">
                    {clarificationPrompt && (
                        <div className="omniguide-other-input__clarification">
                            {clarificationPrompt}
                        </div>
                    )}

                    <div className="omniguide-other-input__field-wrapper">
                        <input
                            ref={inputRef}
                            type="text"
                            className={`omniguide-other-input__field ${otherError ? 'omniguide-other-input__field--error' : ''}`}
                            value={otherText}
                            onChange={handleOtherTextChange}
                            onKeyDown={handleKeyDown}
                            placeholder="Enter your answer..."
                            maxLength={maxOtherLength}
                            disabled={isOtherProcessing}
                            aria-label="Custom answer"
                            aria-invalid={!!otherError}
                            aria-describedby={otherError ? 'other-error' : undefined}
                        />
                        <span className="omniguide-other-input__counter">
                            {otherText.length}/{maxOtherLength}
                        </span>
                    </div>

                    {otherError && (
                        <div id="other-error" className="omniguide-other-input__error" role="alert">
                            {otherError.message}
                        </div>
                    )}

                    <div className="omniguide-other-input__actions">
                        <button
                            type="button"
                            className="omniguide-other-input__cancel"
                            onClick={handleCancelOther}
                            disabled={isOtherProcessing}
                        >
                            Cancel
                        </button>
                        <button
                            type="button"
                            className="omniguide-other-input__submit"
                            onClick={handleOtherSubmit}
                            disabled={!otherText.trim() || isOtherProcessing}
                        >
                            {isOtherProcessing ? (
                                <>
                                    <LoadingSpinner />
                                    <span>Submitting...</span>
                                </>
                            ) : (
                                'Submit'
                            )}
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}
