import React, { useEffect, useRef, useState } from 'react';
import { DiscoveryStepIndicator } from './DiscoveryStepIndicator.js';
import type { AnsweredQuestionEntry } from './DiscoveryStepIndicator.js';
import { DiscoveryQuestionStep } from './DiscoveryQuestionStep.js';
import type { DiscoveryQuestion, OtherError } from './DiscoveryQuestionStep.js';
import type { DiscoveryAnswer } from './DiscoveryOptionButton.js';
import type { AnswerChoice } from './DiscoveryAutocomplete.js';

export interface DiscoveryQuestionnaireProps {
    questions: DiscoveryQuestion[];
    currentStep: number;
    answeredIntents: Record<string, { answer: string; answer_id?: string; [key: string]: unknown }>;
    onSelectAnswer: (questionId: string, answer: DiscoveryAnswer) => void;
    /** Critical Filter Question pick — see DiscoveryQuestionStep.onSelectChoice. */
    onSelectChoice?: (questionId: string, choice: AnswerChoice) => void;
    onNext: () => void;
    onPrevious: () => void;
    onSubmit: () => void;
    onStepClick?: (index: number) => void;
    submitButtonText?: string;
    subtitle?: string;
    /**
     * Eyebrow label (e.g. "Shopping Guide") shown in the compact band header.
     * When set, the questionnaire renders the band-style header (brand mark +
     * eyebrow + divider + promise on one strip, with the question below and the
     * progress hairline pushed right). When omitted, the legacy header renders —
     * keeps product-fit unaffected.
     */
    eyebrow?: string;
    /** Close/minimise handler — when set (with `eyebrow`), the band shows an X top-right. */
    onClose?: () => void;
    /** Security & Privacy disclosure text — when set (with `eyebrow`), a collapsible row renders at the band foot. */
    privacyBlurb?: string;
    /**
     * Merchant brand logo URL (SOI-757). When set, replaces the default
     * Omniguide AI mark in the questionnaire header with the merchant's own
     * logo. Sourced from `config.ui.merchantLogoUrl`.
     */
    merchantLogoUrl?: string;
    classPrefix?: string;
    dynamicMode?: boolean;
    answeredQuestions?: AnsweredQuestionEntry[];
    questionNumber?: number;
    /**
     * Fixed step total for the dynamic/conversational flow (e.g. 3). Adaptive
     * mode only ever holds the current question, so `questions.length` is 1 and
     * the progress count would read "2 / 1". When set, the indicator shows this
     * total instead — clamped up to `questionNumber` if the flow ever runs long,
     * so the count never goes backwards (e.g. "4 / 3" → "4 / 4").
     */
    totalStepsHint?: number;
    onOtherSubmit?: (text: string) => void;
    isOtherProcessing?: boolean;
    otherError?: OtherError | null;
    clarificationPrompt?: string | null;
    onClearOtherError?: () => void;
}

