const ArrowRightIcon = () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path
            d="M5 12H19M19 12L12 5M19 12L12 19"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        />
    </svg>
);

const ArrowLeftIcon = () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path
            d="M19 12H5M5 12L12 5M5 12L12 19"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
        />
    </svg>
);

const CloseIcon = () => (
    <svg viewBox="0 0 14 14" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" aria-hidden="true">
        <path d="M2 2 L12 12 M12 2 L2 12" />
    </svg>
);

const LockIcon = () => (
    <svg viewBox="0 0 24 24" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
        <rect x="4" y="11" width="16" height="9" rx="2" />
        <path d="M8 11V7a4 4 0 0 1 8 0v4" />
    </svg>
);

const ChevronIcon = () => (
    <svg viewBox="0 0 10 10" width="10" height="10" aria-hidden="true">
        <path d="M2 3.5 L5 6.5 L8 3.5" stroke="currentColor" strokeWidth="1.5" fill="none" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
);

export function DiscoveryQuestionnaire({
    questions,
    currentStep,
    answeredIntents,
    onSelectAnswer,
    onSelectChoice,
    onNext,
    onPrevious,
    onSubmit,
    onStepClick,
    submitButtonText = 'See Recommendations',
    subtitle,
    eyebrow,
    onClose,
    privacyBlurb,
    merchantLogoUrl,
    classPrefix = 'omniguide-cr',
    dynamicMode = false,
    answeredQuestions = [],
    questionNumber = 0,
    totalStepsHint,
    onOtherSubmit,
    isOtherProcessing = false,
    otherError = null,
    clarificationPrompt = null,
    onClearOtherError,
}: DiscoveryQuestionnaireProps): JSX.Element {
    const [secOpen, setSecOpen] = useState(false);
    const currentQuestion = questions[currentStep];
    const currentAnswer = currentQuestion?.id ? answeredIntents[currentQuestion.id] : undefined;
    const isLastStep = currentStep === questions.length - 1;
    const isFirstStep = currentStep === 0;
    const hasSelection = !!currentAnswer;

    const wasPreAnsweredRef = useRef<Record<string, boolean>>({});
    const questionId = currentQuestion?.id;

    useEffect(() => {
        if (questionId && wasPreAnsweredRef.current[questionId] === undefined) {
            wasPreAnsweredRef.current[questionId] = hasSelection;
        }
    }, [questionId, hasSelection]);

    const wasPreAnswered = questionId ? wasPreAnsweredRef.current[questionId] : false;

    const handleNextClick = () => {
        if (isLastStep) {
            onSubmit();
        } else {
            onNext();
        }
    };

    const handleAnswerSelect = (qId: string, answer: DiscoveryAnswer) => {
        onSelectAnswer(qId, answer);

        if (!wasPreAnswered) {
            setTimeout(() => {
                handleNextClick();
            }, 300);
        }
    };

    const mark = merchantLogoUrl ? (
        <img
            className={`${classPrefix}-questionnaire__logo`}
            src={merchantLogoUrl}
            alt=""
            aria-hidden="true"
        />
    ) : (
        <span className={`${classPrefix}-questionnaire__icon`}>
            <AIIcon />
        </span>
    );

    // Adaptive mode only holds the current question, so questions.length is 1.
    // Use the fixed hint when provided, clamped up to the current question
    // number so the denominator never falls behind the numerator.
    const effectiveTotalSteps =
        dynamicMode && totalStepsHint
            ? Math.max(totalStepsHint, questionNumber)
            : questions.length;

    const stepIndicator = (
        <DiscoveryStepIndicator
            currentStep={currentStep}
            totalSteps={effectiveTotalSteps}
            answeredIntents={answeredIntents}
            questions={questions}
            onStepClick={onStepClick}
            classPrefix={classPrefix}
            showAnswerPills={false}
            dynamicMode={dynamicMode}
            answeredQuestions={answeredQuestions}
            questionNumber={questionNumber}
        />
    );

    const titleEl = (
        <h2 className={`${classPrefix}-questionnaire__title`}>
            {!dynamicMode && isLastStep && (
                <span className={`${classPrefix}-questionnaire__last`}>Last one.</span>
            )}
            {currentQuestion?.question || 'Loading...'}
        </h2>
    );

    return (
        <div className={`${classPrefix}-questionnaire${eyebrow ? ` ${classPrefix}-questionnaire--band` : ''}`}>
            {eyebrow && onClose && (
                <button
                    type="button"
                    className={`${classPrefix}-questionnaire__close`}
                    aria-label="Minimize shopping guide"
                    onClick={onClose}
                >
                    <CloseIcon />
                </button>
            )}
            <div className={`${classPrefix}-questionnaire__header`}>
                {eyebrow ? (
                    <>
                        <div className={`${classPrefix}-questionnaire__topline`}>
                            <span className={`${classPrefix}-questionnaire__brand`}>
                                {mark}
                                <span className={`${classPrefix}-questionnaire__eyebrow`}>{eyebrow}</span>
                            </span>
                            {subtitle && (
                                <span className={`${classPrefix}-questionnaire__promise`}>{subtitle}</span>
                            )}
                            {stepIndicator}
                        </div>
                        {titleEl}
                    </>
                ) : (
                    <>
                        <div className={`${classPrefix}-questionnaire__header-row`}>
                            <div className={`${classPrefix}-questionnaire__title-row`}>
                                {mark}
                                {titleEl}
                            </div>
                            {stepIndicator}
                        </div>
                        {subtitle && (
                            <p className={`${classPrefix}-questionnaire__subtitle`}>
                                {subtitle}
                            </p>
                        )}
                    </>
                )}
            </div>

            {currentQuestion && (
                <DiscoveryQuestionStep
                    question={currentQuestion}
                    selectedAnswer={currentAnswer}
                    onSelectAnswer={(answer) => handleAnswerSelect(currentQuestion.id, answer)}
                    onSelectChoice={onSelectChoice ? (choice) => onSelectChoice(currentQuestion.id, choice) : undefined}
                    onOtherSubmit={onOtherSubmit ? (_questionId, text) => onOtherSubmit(text) : undefined}
                    isOtherProcessing={isOtherProcessing}
                    otherError={otherError}
                    clarificationPrompt={clarificationPrompt}
                    onClearOtherError={onClearOtherError}
                />
            )}

            {!dynamicMode && (
                <div className={`${classPrefix}-nav`}>
                    {!isFirstStep ? (
                        <button
                            type="button"
                            className={`${classPrefix}-nav__prev`}
                            onClick={onPrevious}
                        >
                            <div className={`${classPrefix}-nav__prev-icon`}>
                                <ArrowLeftIcon />
                            </div>
                            <span className={`${classPrefix}-nav__prev-text`}>Previous</span>
                        </button>
                    ) : (
                        <div />
                    )}

                    {wasPreAnswered ? (
                        <button
                            type="button"
                            className={`${classPrefix}-nav__next`}
                            data-disabled={!hasSelection}
                            onClick={handleNextClick}
                            disabled={!hasSelection}
                        >
                            <span className={`${classPrefix}-nav__next-text`}>
                                {isLastStep ? submitButtonText : 'Next'}
                            </span>
                            <div className={`${classPrefix}-nav__next-icon`}>
                                <ArrowRightIcon />
                            </div>
                        </button>
                    ) : (
                        <div />
                    )}
                </div>
            )}

            {eyebrow && privacyBlurb && (
                <div className={`${classPrefix}-questionnaire__sec${secOpen ? ' is-open' : ''}`}>
                    <button
                        type="button"
                        className={`${classPrefix}-questionnaire__sec-toggle`}
                        aria-expanded={secOpen}
                        onClick={() => setSecOpen((v) => !v)}
                    >
                        <span className={`${classPrefix}-questionnaire__sec-lock`} aria-hidden="true">
                            <LockIcon />
                        </span>
                        <span>Security &amp; Privacy</span>
                        <span className={`${classPrefix}-questionnaire__sec-chev`} aria-hidden="true">
                            <ChevronIcon />
                        </span>
                    </button>
                    {secOpen && (
                        <div className={`${classPrefix}-questionnaire__sec-body`} role="region" aria-label="Security and privacy">
                            <p>{privacyBlurb}</p>
                        </div>
                    )}
                </div>
            )}
        </div>
    );
}
