/**
 * Hook for rotating status messages during loading states.
 * Supports both array messages (rotate) and string messages (static).
 */

import { useState, useEffect, useCallback } from 'react';
import type { UseStatusMessageReturn } from '../types.js';

const DEFAULT_ROTATION_INTERVAL = 2500; // 2.5 seconds

export function useStatusMessage(
  processingStatus: string | null,
  statusMessages: Record<string, string | string[]>,
  rotationInterval: number = DEFAULT_ROTATION_INTERVAL,
): UseStatusMessageReturn {
  const [messageIndex, setMessageIndex] = useState(0);

  // Reset index when status changes
  useEffect(() => {
    if (!processingStatus) {
      setMessageIndex(0);
      return;
    }

    const messages = statusMessages[processingStatus];
    if (!messages || !Array.isArray(messages) || messages.length <= 1) {
      return;
    }

    const interval = setInterval(() => {
      setMessageIndex((prevIndex) => (prevIndex + 1) % messages.length);
    }, rotationInterval);

    return () => clearInterval(interval);
  }, [processingStatus, statusMessages, rotationInterval]);

  const getStatusMessage = useCallback((): string | null => {
    if (!processingStatus) return null;

    const messages = statusMessages[processingStatus] ?? statusMessages['processing'];
    if (!messages) return null;

    if (Array.isArray(messages)) {
      return messages[messageIndex % messages.length] ?? null;
    }

    return messages;
  }, [processingStatus, statusMessages, messageIndex]);

  return { statusMessage: getStatusMessage(), getStatusMessage };
}
