/**
 * QuestionnaireTeaser — Compact, borderless guide header (SOI-757).
 *
 * A single low-profile row: brand mark + eyebrow/title/subtitle on the left,
 * and up to two actions on the right — "Start guide" (opens the questionnaire)
 * and an optional "or, ask a question" (opens the freeform ask flow). An
 * optional close (X) dismisses the teaser.
 *
 * Config-gated: only rendered when `features.questionnaireTeaser.categoryGuide`
 * or `features.questionnaireTeaser.productFit` is true.
 *
 * The secondary ask button and the close X render only when their respective
 * callbacks (`onAsk` / `onClose`) are supplied — so the product-fit teaser,
 * which passes neither, keeps its original single-CTA layout.
 */

import React, { type ReactNode } from 'react';

// ── Types ──────────────────────────────────────────────────────────

export interface QuestionnaireTeaserProps {
  /** Content to show inside the teaser (the actual questionnaire) */
  children: ReactNode;
  /** Small uppercase label above the title (e.g. "Shopping Guide") */
  eyebrow?: string;
  /** Title line (e.g. "Find your perfect scope") */
  headline?: string;
  /** Sub-line beneath the title (e.g. "Answer 3 quick questions") */
  subtitle?: string;
  /** Primary CTA label */
  ctaLabel?: string;
  /** Secondary "ask a question" CTA label. Button renders only when `onAsk` is set. */
  askLabel?: string;
  /** Merchant brand logo shown in the mark. Falls back to a default mark. */
  merchantLogoUrl?: string;
  /**
   * CSS class prefix for the teaser wrapper. Use to scope styles
   * per feature: 'omniguide-cr' (category) or 'omniguide-pr' (product).
   */
  classPrefix?: string;
  /** Callback when "Start guide" is clicked (expands the questionnaire). */
  onExpand?: () => void;
  /** Opens the freeform ask flow. When provided, renders the secondary ask button. */
  onAsk?: () => void;
  /** Dismisses the teaser. When provided, renders the close (X) button. */
  onClose?: () => void;
}

// ── Icons (inline SVG) ─────────────────────────────────────────────

function ChevronIcon(): JSX.Element {
  return (
    <svg
      width="13"
      height="13"
      viewBox="0 0 12 12"
      fill="none"
      stroke="currentColor"
      strokeWidth="2.2"
      strokeLinecap="round"
      strokeLinejoin="round"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path d="M4.5 2.5l4 3.5-4 3.5" />
    </svg>
  );
}

function CloseIcon(): JSX.Element {
  return (
    <svg
      width="13"
      height="13"
      viewBox="0 0 14 14"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <path d="M2 2l10 10M12 2L2 12" />
    </svg>
  );
}

function DefaultMark(): JSX.Element {
  return (
    <svg width="22" height="22" viewBox="0 0 600 583" fill="currentColor" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path d="M570.746 170.699C556.464 140.767 536.93 112.67 512.11 87.8792C487.29 63.0883 459.239 43.5494 429.315 29.2257C347.731 -9.74192 252.195 -9.74192 170.648 29.2257C140.725 43.5127 112.637 63.0516 87.853 87.8792C63.0695 112.707 43.5364 140.767 29.217 170.699C-9.73901 252.307 -9.73901 347.872 29.217 429.443C43.4997 459.376 63.0328 487.472 87.853 512.263L158.569 583L170.648 570.917L300 441.526L158.569 300.053L300 158.579L441.431 300.053L300 441.526L429.352 570.917L441.431 583L512.147 512.263C536.931 487.472 556.464 459.376 570.783 429.443C609.739 347.835 609.739 252.271 570.783 170.699H570.746Z" />
    </svg>
  );
}

// ── Component ──────────────────────────────────────────────────────

export function QuestionnaireTeaser({
  children,
  eyebrow = 'Shopping Guide',
  headline = 'Find your perfect match',
  subtitle = 'Answer 3 quick questions',
  ctaLabel = 'Start guide',
  askLabel = 'or, ask a question',
  merchantLogoUrl,
  classPrefix = 'omniguide-cr',
  onExpand,
  onAsk,
  onClose,
}: QuestionnaireTeaserProps): JSX.Element {
  const base = `${classPrefix}-questionnaire-teaser`;

  return (
    <div className={base}>
      {onClose ? (
        <button
          type="button"
          className={`${base}__close`}
          aria-label="Dismiss shopping guide"
          onClick={() => onClose()}
        >
          <CloseIcon />
        </button>
      ) : null}
      <div className={`${base}__header`}>
        <span className={`${base}__mark`} aria-hidden="true">
          {merchantLogoUrl ? (
            <img className={`${base}__mark-img`} src={merchantLogoUrl} alt="" />
          ) : (
            <DefaultMark />
          )}
        </span>
        <span className={`${base}__text`}>
          <span className={`${base}__eyebrow`}>{eyebrow}</span>
          <span className={`${base}__headline`}>{headline}</span>
          <span className={`${base}__subtitle`}>{subtitle}</span>
        </span>
        <span className={`${base}__actions`}>
          <button type="button" className={`${base}__cta`} onClick={() => onExpand?.()}>
            {ctaLabel}
            <ChevronIcon />
          </button>
          {onAsk ? (
            <button type="button" className={`${base}__ask`} onClick={() => onAsk()}>
              {askLabel}
            </button>
          ) : null}
        </span>
      </div>
      <div className={`${base}__body`}>{children}</div>
    </div>
  );
}
