import React from 'react';

export interface AnsweredQuestionEntry {
    question: {
        id?: string;
        question?: string;
        summary?: string;
    };
    answer: {
        answer: string;
        [key: string]: unknown;
    };
}

export interface DiscoveryStepIndicatorProps {
    currentStep: number;
    totalSteps: number;
    answeredIntents: Record<string, { answer: string; answer_id?: string; [key: string]: unknown }>;
    questions: Array<{ id?: string; question?: string; summary?: string }>;
    onStepClick?: (index: number) => void;
    classPrefix?: string;
    showAnswerPills?: boolean;
    dynamicMode?: boolean;
    answeredQuestions?: AnsweredQuestionEntry[];
    questionNumber?: number;
}

export function DiscoveryStepIndicator({
    currentStep,
    totalSteps,
    answeredIntents,
    questions,
    onStepClick,
    classPrefix = 'omniguide-cr',
    showAnswerPills = true,
    dynamicMode = false,
    answeredQuestions = [],
    questionNumber = 0,
}: DiscoveryStepIndicatorProps): JSX.Element {
    if (dynamicMode) {
        // Fill by current step position when a questionNumber is supplied (the
        // band flow — matches the design's step-based hairline); otherwise fall
        // back to the answered-count behaviour for callers that don't pass one.
        const progressBasis = questionNumber > 0 ? questionNumber : answeredQuestions.length;
        const progressPct = totalSteps > 0
            ? Math.round((progressBasis / totalSteps) * 100)
            : 0;
        const showProgress = totalSteps > 0;

        return (
            <div
                className={`${classPrefix}-steps ${classPrefix}-steps--dynamic`}
                style={showProgress ? { '--omniguide-progress': `${progressPct}%` } as React.CSSProperties : undefined}
            >
                {answeredQuestions.map((aq, index) => {
                    const question = aq.question;
                    const answer = aq.answer;
                    const hasSummary = !!question?.summary;
                    const pillText = hasSummary
                        ? `${question.summary}: ${answer.answer}`
                        : answer.answer;

                    return (
                        <button
                            key={question?.id || index}
                            type="button"
                            className={`${classPrefix}-step ${classPrefix}-step--pill`}
                            onClick={() => onStepClick?.(index)}
                            title={question?.question}
                        >
                            {pillText}
                        </button>
                    );
                })}

                <div className={`${classPrefix}-steps__progress`}>
                    {showProgress && (
                        <div className={`${classPrefix}-steps__progress-track`} />
                    )}
                    {questionNumber > 0 && (
                        <span className={`${classPrefix}-steps__progress-count`}>
                            {showProgress ? `${questionNumber} / ${totalSteps}` : questionNumber}
                        </span>
                    )}
                </div>
            </div>
        );
    }

    const progressPct = Math.round(((currentStep + 1) / totalSteps) * 100);

    return (
        <div
            className={`${classPrefix}-steps`}
            style={{ '--omniguide-progress': `${progressPct}%` } as React.CSSProperties}
        >
            {Array.from({ length: totalSteps }).map((_, index) => {
                const question = questions[index];
                const answer = question?.id ? answeredIntents[question.id] : undefined;
                const isCompleted = !!answer;
                const isCurrent = index === currentStep;
                const hasSummary = !!question?.summary;
                const stepNumber = index + 1;

                if (!showAnswerPills) {
                    let circleClass = `${classPrefix}-step ${classPrefix}-step--circle`;

                    if (isCurrent) {
                        circleClass += ` ${classPrefix}-step--current`;
                    } else if (isCompleted) {
                        circleClass += ` ${classPrefix}-step--answered`;
                    } else {
                        circleClass += ` ${classPrefix}-step--unvisited`;
                    }

                    return (
                        <div
                            key={question?.id || index}
                            className={circleClass}
                        >
                            {stepNumber}
                        </div>
                    );
                }

                if (isCompleted && !isCurrent) {
                    const pillText = hasSummary
                        ? `${question!.summary}: ${answer!.answer}`
                        : answer!.answer;
                    return (
                        <button
                            key={question?.id || index}
                            type="button"
                            className={`${classPrefix}-step ${classPrefix}-step--pill`}
                            onClick={() => onStepClick?.(index)}
                            title={question?.question}
                        >
                            {pillText}
                        </button>
                    );
                }

                if (isCurrent) {
                    return (
                        <div
                            key={question?.id || index}
                            className={`${classPrefix}-step ${classPrefix}-step--circle ${classPrefix}-step--current`}
                        >
                            {stepNumber}
                        </div>
                    );
                }

                return (
                    <div
                        key={question?.id || index}
                        className={`${classPrefix}-step ${classPrefix}-step--circle ${classPrefix}-step--unvisited`}
                    >
                        {stepNumber}
                    </div>
                );
            })}
        </div>
    );
}
