/**
 * useDiscoveryAnswerStorage
 *
 * Shared hook for persisting and restoring discovery questionnaire answers.
 * Used by both useProductWebSocket and useCategoryWebSocket.
 * Platform-agnostic — works with any AnsweredIntentsStorage implementation.
 */

import { useCallback } from 'react';

// =========================================
// Types
// =========================================

export interface AnsweredIntentEntry {
  question_id: string;
  answer_id: string | null;
  answer_text: string;
  is_other: boolean;
  question: Record<string, unknown> | null;
  product_type_id?: number;
}

export interface DiscoveryAnswerStorageAdapter {
  /** Load answered intents from storage, optionally filtered by productTypeId */
  load: (productTypeId?: number | string | null) => Record<string, AnsweredIntentEntry>;
  /** Save answered intents to storage */
  save: (intents: Record<string, AnsweredIntentEntry>) => void;
  /** Convert a raw ID to a discovery-prefixed ID */
  toDiscoveryId: (id: string) => string;
  /** Get answered intents formatted for API consumption */
  getForApi: (productTypeId?: number | string | null) => Record<string, Record<string, unknown>>;
}

export interface RestoredAnswer {
  question: Record<string, unknown>;
  answer: { answer_id: string | null; answer: string };
}

export interface UseDiscoveryAnswerStorageReturn {
  saveAnswer: (questionId: string, answerId: string | null, answerText: string, isOther?: boolean, question?: Record<string, unknown> | null) => void;
  restoreFromStorage: () => RestoredAnswer[];
  hasStoredSession: () => boolean;
  getStoredAnswerCount: () => number;
  clearStorage: () => void;
}

// =========================================
// Hook
// =========================================

export function useDiscoveryAnswerStorage(
  storageAdapter: DiscoveryAnswerStorageAdapter,
  productTypeId: number | string | null = null,
): UseDiscoveryAnswerStorageReturn {
  const saveAnswer = useCallback(
    (
      questionId: string,
      answerId: string | null,
      answerText: string,
      isOther: boolean = false,
      question: Record<string, unknown> | null = null,
    ) => {
      // Load all intents (unfiltered) to preserve answers from other product types
      const currentIntents = storageAdapter.load();
      const storageKey = storageAdapter.toDiscoveryId(questionId);

      currentIntents[storageKey] = {
        question_id: storageKey,
        answer_id: answerId ? storageAdapter.toDiscoveryId(answerId) : null,
        answer_text: answerText,
        is_other: isOther,
        question,
        product_type_id: productTypeId ? Number(productTypeId) : undefined,
      };

      storageAdapter.save(currentIntents);
    },
    [storageAdapter, productTypeId],
  );

  const restoreFromStorage = useCallback((): RestoredAnswer[] => {
    const storedIntents = storageAdapter.load(productTypeId);
    const restored: RestoredAnswer[] = [];

    for (const intent of Object.values(storedIntents)) {
      if (intent.question) {
        restored.push({
          question: intent.question,
          answer: {
            answer_id: intent.answer_id,
            answer: intent.answer_text,
          },
        });
      }
    }

    return restored;
  }, [storageAdapter, productTypeId]);

  const hasStoredSession = useCallback((): boolean => {
    const storedIntents = storageAdapter.load(productTypeId);
    return Object.keys(storedIntents).length > 0;
  }, [storageAdapter, productTypeId]);

  const getStoredAnswerCount = useCallback((): number => {
    const storedIntents = storageAdapter.load(productTypeId);
    return Object.keys(storedIntents).length;
  }, [storageAdapter, productTypeId]);

  const clearStorage = useCallback((): void => {
    storageAdapter.save({});
  }, [storageAdapter]);

  return {
    saveAnswer,
    restoreFromStorage,
    hasStoredSession,
    getStoredAnswerCount,
    clearStorage,
  };
}
