/**
 * Recommendation field normalization (SOI-809).
 *
 * The backend (SOI-801 match ranking %, SOI-802 bullet callouts) returns
 * per-product match data, but field names vary across endpoints/versions.
 * These helpers map the raw payload onto the typed OmniguideProduct fields
 * (matchPct / summary / bullets / detail / reasons / rank), alias-tolerant
 * like the existing question normalizer. Unknown fields pass through unchanged.
 */
import type { OmniguideProduct, ProductReason } from './types.js';

type Raw = Record<string, unknown>;

/** First defined value across a list of candidate keys. */
function pick(raw: Raw, keys: string[]): unknown {
  for (const k of keys) {
    if (raw[k] !== undefined && raw[k] !== null) return raw[k];
  }
  return undefined;
}

function pickString(raw: Raw, keys: string[]): string | undefined {
  const v = pick(raw, keys);
  return typeof v === 'string' && v.trim() ? v : undefined;
}

function pickNumber(raw: Raw, keys: string[]): number | undefined {
  const v = pick(raw, keys);
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  if (typeof v === 'string' && v.trim() && Number.isFinite(Number(v))) return Number(v);
  return undefined;
}

/** Bullet list — accepts an array of strings, or {text}/{label} objects. */
function pickBullets(raw: Raw, keys: string[]): string[] | undefined {
  const v = pick(raw, keys);
  if (!Array.isArray(v)) return undefined;
  const out = v
    .map((item) => {
      if (typeof item === 'string') return item.trim();
      if (item && typeof item === 'object') {
        const o = item as Raw;
        const s = o['text'] ?? o['label'] ?? o['value'];
        return typeof s === 'string' ? s.trim() : '';
      }
      return '';
    })
    .filter((s): s is string => !!s);
  return out.length ? out : undefined;
}

/** Labeled reason chips — accepts {k,v} | {label,value} | {key,value} | {name,value}. */
function pickReasons(raw: Raw, keys: string[]): ProductReason[] | undefined {
  const v = pick(raw, keys);
  if (!Array.isArray(v)) return undefined;
  const out: ProductReason[] = [];
  for (const item of v) {
    if (!item || typeof item !== 'object') continue;
    const o = item as Raw;
    const label = o['label'] ?? o['k'] ?? o['key'] ?? o['name'];
    const value = o['value'] ?? o['v'] ?? o['text'];
    if (typeof label === 'string' && typeof value === 'string' && label.trim() && value.trim()) {
      out.push({ label: label.trim(), value: value.trim() });
    }
  }
  return out.length ? out : undefined;
}

/**
 * Coerce a single raw number to a 0–100 match percentage. A value in (0,1] is
 * treated as a fraction and scaled; anything above 1 is taken as an already-
 * percentage value. Shared so callers (e.g. the PDP fit bridge) don't hand-copy
 * the heuristic.
 */
export function toMatchPct(raw: number): number {
  return clampPct(raw > 0 && raw <= 1 ? raw * 100 : raw);
}

/**
 * Coerce a raw match value to a 0–100 percentage.
 * Dedicated percentage fields are used as-is; a bare `score` in (0,1] is
 * treated as a fraction and scaled, otherwise used directly.
 */
export function normalizeMatchPct(raw: Raw): number | undefined {
  const explicit = pickNumber(raw, ['match_pct', 'matchPct', 'match_percentage', 'matchPercentage', 'match_score', 'pct', 'percentage']);
  if (explicit !== undefined) return clampPct(explicit > 1 ? explicit : explicit * 100);
  const score = pickNumber(raw, ['score']);
  if (score === undefined) return undefined;
  return toMatchPct(score);
}

export function clampPct(n: number): number {
  return Math.max(0, Math.min(100, Math.round(n)));
}

/**
 * Normalize a single raw recommendation product. Returns a typed
 * OmniguideProduct with match fields filled where present; all original
 * keys are preserved (passthrough).
 */
export function normalizeRecommendedProduct(raw: Raw): OmniguideProduct {
  const sku = pickString(raw, ['sku', 'SKU']) ?? '';
  const matchPct = normalizeMatchPct(raw);
  const rank = pickNumber(raw, ['rank']);
  const summary = pickString(raw, ['summary', 'why', 'one_liner', 'oneLiner', 'headline', 'statement']);
  const bullets = pickBullets(raw, ['bullets', 'why_bullets', 'whyBullets', 'highlights', 'callouts']);
  const detail = pickString(raw, ['detail', 'why_more', 'whyMore', 'explanation', 'details', 'long_explanation']);
  const reasons = pickReasons(raw, ['reasons', 'tags', 'attributes', 'reason_tags', 'reasonTags', 'spec_highlights']);

  return {
    ...(raw as OmniguideProduct),
    sku,
    ...(matchPct !== undefined ? { matchPct } : {}),
    ...(rank !== undefined ? { rank } : {}),
    ...(summary !== undefined ? { summary } : {}),
    ...(bullets !== undefined ? { bullets } : {}),
    ...(detail !== undefined ? { detail } : {}),
    ...(reasons !== undefined ? { reasons } : {}),
  };
}

/** Normalize a list of raw recommendation products (no-op for non-arrays). */
export function normalizeRecommendedProducts(raw: unknown): OmniguideProduct[] {
  if (!Array.isArray(raw)) return [];
  return raw.map((p) => normalizeRecommendedProduct((p ?? {}) as Raw));
}
